-- Source MySQL pour TP ETL Datawarehouse
DROP DATABASE IF EXISTS tp_printer_sales;
CREATE DATABASE tp_printer_sales 
ENCODING = 'UTF8';
USE tp_printer_sales;


CREATE TABLE hr_vendeurs (
    seller_code VARCHAR(10) PRIMARY KEY,
    first_name VARCHAR(60),
    last_name VARCHAR(60),
    email VARCHAR(120),
    salary DECIMAL(12,2),
    hire_date DATE,
    home_country VARCHAR(60),
    home_region VARCHAR(80),
    home_city VARCHAR(80),
    manager_code VARCHAR(10)
);

CREATE TABLE ref_clients (
    customer_code VARCHAR(10) PRIMARY KEY,
    customer_name VARCHAR(150),
    sector VARCHAR(50),
    country VARCHAR(60),
    region_name VARCHAR(80),
    city VARCHAR(80),
    postal_code VARCHAR(20),
    created_at DATE
);

CREATE TABLE ref_produits (
    product_code VARCHAR(10) PRIMARY KEY,
    product_name VARCHAR(120),
    category_name VARCHAR(60),
    range_name VARCHAR(50),
    list_price DECIMAL(12,2),
    active_flag INT,
    launch_date DATE
);

CREATE TABLE sales_orders (
    order_id INT PRIMARY KEY,
    order_date DATE,
    seller_code VARCHAR(10),
    customer_code VARCHAR(10),
    product_code VARCHAR(10),
    quantity INT,
    unit_price DECIMAL(12,2),
    discount_pct DECIMAL(5,2),
    order_status VARCHAR(20),
    promised_delivery_date DATE,
    created_at TIMESTAMP
);

